endpoint.request:
opportunities: id; name string NOT NULL index; registry_id FK registries NOT NULL restrict;
company_id FK companies NULL restrict; company_site_id FK company_sites NULL restrict;
operational_site_id FK operational_sites NULL restrict; business_function_id FK
business_functions NULL restrict; referent_id / commercial_id / reporter_id FK referents
NULL restrict; supervisor_id FK users NULL restrict; source_id FK sources NULL restrict;
product_category_id FK product_categories NULL restrict; lead_id FK leads NULL UNIQUE
restrict; start_date date NULL; estimated_value decimal(15,2) NULL;
expected_close_date date NULL; success_probability unsignedTinyInteger NULL; timestamps.
opportunity_user: opportunity_id + user_id (cascade), position unsigned;
unique(opportunity_id,user_id), unique(opportunity_id,position).
